#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-21

# strict-mode: opt-out sourced library — `set -euo pipefail` here would impose
# strict mode on every caller (run-skill-eval.sh, run-quality-eval.sh) and
# change their existing error handling. Callers set their own strict mode; every
# function below returns a status instead of relying on -e.
# =============================================================================
# Budget governor — refuse an eval run the subscription cannot afford
# =============================================================================
#
# WHY THIS EXISTS
#
# On 2026-07-20 a skill-eval run fired 20 `claude -p` calls and every one
# returned HTTP 429. Zero succeeded, the very first call was already rejected,
# and the job burned 72 seconds to discover a fact it could have learned in
# one: the plan's WEEKLY cap was already exhausted before the job started.
#
#   You've hit your weekly limit    resets Jul 21, 11pm (UTC)
#
# The runner shares one subscription pool with interactive Claude Code use, so
# a heavy day of interactive work can starve CI. A weekly cap cannot be waited
# out inside a run, and no amount of backoff or concurrency tuning changes it.
# The only useful response is to notice early and skip loudly.
#
# WHAT THIS DOES
#
#   record_cap_exhausted <raw-limit-message>
#       Called when a generation is classified as 429. Persists the observation
#       and, when the message carries a parseable reset time, the epoch to wait
#       for.
#
#   budget_check
#       Called BEFORE a run commits to N calls. Returns 0 (proceed) unless a
#       previously recorded cap is still in force, in which case it prints a
#       loud skip and returns 3.
#
# DELIBERATELY CONSERVATIVE: it refuses ONLY when it has a parsed reset time
# that is still in the future. An unparseable message warns and proceeds. A
# governor that blocks on a guess would be worse than the problem it fixes,
# because it would silently stop measuring for the wrong reason, which is the
# exact failure class this subsystem has spent its history removing.
#
# State lives under tests/evals/results/, which .gitignore already excludes, so
# a local cap observation never travels to another machine.
# =============================================================================

_bg_state_file() {
  local root="${REPO_ROOT:-$(cd "$(dirname "${BASH_SOURCE[0]}")/../../../.." && pwd)}"
  echo "${root}/tests/evals/results/.budget-state.json"
}

# Convert a limit message's reset clause to an epoch. Echoes the epoch on
# success, nothing on failure. Handles the observed shape "resets Jul 21, 11pm
# (UTC)" and a bare epoch. date(1) differs between BSD (macOS) and GNU (ubuntu
# runners), so both invocations are attempted.
_bg_parse_reset_epoch() {
  local msg="$1" clause epoch

  # Bare epoch seconds, e.g. "usage limit reached|1784500000". Checked FIRST:
  # that shape carries no "resets" clause, so gating on the clause below would
  # make this branch unreachable. Caught by test-budget-governor.sh.
  epoch=$(printf '%s' "$msg" | grep -oE '[0-9]{10,}' | head -1)
  if [[ -n "$epoch" ]]; then printf '%s' "$epoch"; return 0; fi

  clause=$(printf '%s' "$msg" | sed -n 's/.*[Rr]esets \(.*\)/\1/p' | tr -d '\r')
  [[ -z "$clause" ]] && return 0

  # "Jul 21, 11pm (UTC)" -> normalise to "Jul 21 <YYYY> 23:00:00"
  local mon day hour ampm year norm
  mon=$(printf '%s' "$clause" | grep -oE '^[A-Z][a-z]{2}')
  day=$(printf '%s' "$clause" | grep -oE '[0-9]{1,2}' | head -1)
  hour=$(printf '%s' "$clause" | grep -oiE '[0-9]{1,2}(am|pm)' | grep -oE '^[0-9]{1,2}')
  ampm=$(printf '%s' "$clause" | grep -oiE '(am|pm)' | head -1 | tr '[:upper:]' '[:lower:]')
  [[ -z "$mon" || -z "$day" || -z "$hour" ]] && return 0

  if [[ "$ampm" == "pm" && "$hour" -lt 12 ]]; then hour=$((hour + 12)); fi
  if [[ "$ampm" == "am" && "$hour" -eq 12 ]]; then hour=0; fi
  # silent: external-api-shape
  year=$(date -u '+%Y' 2>/dev/null)
  norm=$(printf '%s %s %s %02d:00:00' "$mon" "$day" "$year" "$hour")

  # silent: external-api-shape
  epoch=$(date -u -j -f '%b %d %Y %H:%M:%S' "$norm" '+%s' 2>/dev/null || true)
  if [[ -z "$epoch" ]]; then
    # silent: external-api-shape
    epoch=$(date -u -d "$norm" '+%s' 2>/dev/null || true)
  fi
  [[ -n "$epoch" ]] && printf '%s' "$epoch"
}

# Persist a cap observation. Never fails the caller: a governor that breaks the
# run it is meant to protect is a net loss, so the write is best-effort.
record_cap_exhausted() {
  local msg="${1:-}" state epoch now kind payload
  state="$(_bg_state_file)"
  # silent: best-effort
  mkdir -p "$(dirname "$state")" 2>/dev/null || return 0
  # silent: external-api-shape
  now=$(date -u '+%s' 2>/dev/null)
  epoch=$(_bg_parse_reset_epoch "$msg")

  kind="unknown"
  case "$msg" in
    *"weekly limit"*)        kind="weekly" ;;
    *"usage limit reached"*) kind="usage" ;;
    *"ate limit"*)           kind="rolling" ;;
  esac

  payload=$(printf '{\n  "observed_at": %s,\n  "kind": "%s",\n  "reset_epoch": %s,\n  "note": "%s"\n}\n' \
    "${now:-0}" "$kind" "${epoch:-null}" \
    "written by budget-governor.sh on an HTTP 429. reset_epoch null means the message was not parseable, in which case budget_check does NOT block.")

  # silent: best-effort
  printf '%s' "$payload" > "$state" 2>/dev/null || return 0
  return 0
}

# Gate a run. Returns 3 when a known cap is still in force, else 0.
budget_check() {
  local state reset now kind
  state="$(_bg_state_file)"
  [[ -f "$state" ]] || return 0

  # silent: external-api-shape
  reset=$(jq -r '.reset_epoch // "null"' "$state" 2>/dev/null || echo null)
  # silent: external-api-shape
  kind=$(jq -r '.kind // "unknown"' "$state" 2>/dev/null || echo unknown)
  [[ "$reset" == "null" || -z "$reset" ]] && return 0

  # silent: external-api-shape
  now=$(date -u '+%s' 2>/dev/null)
  if [[ "$now" -lt "$reset" ]]; then
    local mins=$(( (reset - now) / 60 ))
    {
      echo ""
      echo "  BUDGET GOVERNOR: refusing to start."
      echo "  A ${kind} cap was hit and has not reset yet (~${mins} min remaining)."
      echo "  Every call would return HTTP 429. This is NOT a skill regression."
      echo "  Clear with: rm ${state}"
      echo ""
    } >&2
    return 3
  fi

  # Reset has passed; drop the stale observation so it cannot block a later run.
  # silent: post-cleanup
  rm -f "$state" 2>/dev/null
  return 0
}
